-- ====================================================================
-- Müllerhof CMS – Seed aller bestehenden Seitentexte
-- Automatisch aus den HTML-Dateien extrahiert.
-- Im Supabase SQL Editor ausführen (einmalig).
-- ====================================================================

ON CONFLICT (page_slug, section_key) DO UPDATE SET
  content    = EXCLUDED.content,
  label      = EXCLUDED.label,
  kind       = EXCLUDED.kind,
  sort_order = EXCLUDED.sort_order,
  updated_at = NOW();
